sys_script.script:
(function executeRule(current, previous) {

    // ----------------------------------------
    // 1. Recursion guard (Since multiple updates happening on the same table)
    // ----------------------------------------

    var GUARD = 'quota_rollup_running';
    if (gs.getSession().getClientData(GUARD) === 'true') {
        return;
    }
    gs.getSession().putClientData(GUARD, 'true');

    try {

        // ----------------------------------------
        // 2. Only Month drives rollup
        // ----------------------------------------
        if (current.period_type != 'month') {
            return;
        }

        if (!current.parent_period) {
            return;
        }

        // ----------------------------------------
        // 3. Roll up to Quarter
        // ----------------------------------------
        var quarterGR = new GlideRecord('x_ctans_incentnow_quota_period');
        if (!quarterGR.get(current.parent_period)) {
            return;
        }

        if (quarterGR.period_type != 'quarter') {
            return;
        }

        var quarterTotal = sumChildren(quarterGR.sys_id, 'month');
        updateSystemRecord(quarterGR, quarterTotal);

        // ----------------------------------------
        // 4. Roll up to Year
        // ----------------------------------------
        if (!quarterGR.parent_period) {
            return;
        }

        var yearGR = new GlideRecord('x_ctans_incentnow_quota_period');
        if (!yearGR.get(quarterGR.parent_period)) {
            return;
        }

        if (yearGR.period_type != 'year') {
            return;
        }

        var yearTotal = sumChildren(yearGR.sys_id, 'quarter');
        updateSystemRecord(yearGR, yearTotal);

        // 5. Update Parent Quota (Annual)
        // ----------------------------------------
        if (current.quota) {
            var parentQuota = new GlideRecord('x_ctans_incentnow_quota');
            if (parentQuota.get(current.quota)) {

                parentQuota.target_value = yearTotal;
                // parentQuota.distribution_method = 'monthly';
                parentQuota.update();
            }
        }

    } finally {
        // ----------------------------------------
        // 6. Clear recursion guard
        // ----------------------------------------
        gs.getSession().putClientData(GUARD, '');
    }

    // =====================================================
    // Helper: Sum child quota values
    // =====================================================

    function sumChildren(parentId, expectedType) {
        var total = 0;
        var ga = new GlideAggregate('x_ctans_incentnow_quota_period');
        ga.addQuery('parent_period', parentId);
        ga.addQuery('period_type', expectedType);
        ga.addAggregate('SUM', 'target_value');
        ga.setGroup(false);
        ga.query();

        if (ga.next()) {
            total = parseFloat(ga.getAggregate('SUM', 'target_value')) || 0;
        }

        return total;
    }

    // =====================================================
    // Helper: Update Quarter / Year safely
    // =====================================================
    function updateSystemRecord(gr, value) {
        gr.setWorkflow(false);
        //  gr.autoSysFields(false);
        gr.target_value = value;
        gr.calculation_mode = 'driven_by_monthly_quota';
        gr.update();
    }


})(current, previous);
